import React from 'react';
import { UserPlus, Package, CreditCard, Home } from 'lucide-react';

function ProcessSection() {
  const steps = [
    {
      icon: <UserPlus size={48} className="text-orange mb-4" />,
      title: "1. Đăng ký",
      description: "Đăng ký tài khoản và nhận địa chỉ kho tại Mỹ."
    },
    {
      icon: <Package size={48} className="text-orange mb-4" />,
      title: "2. Gửi kho Mỹ",
      description: "Gửi hàng đến địa chỉ kho của chúng tôi tại Mỹ."
    },
    {
      icon: <CreditCard size={48} className="text-orange mb-4" />,
      title: "3. Thanh toán",
      description: "Thanh toán cước phí vận chuyển sau khi hàng về."
    },
    {
      icon: <Home size={48} className="text-orange mb-4" />,
      title: "4. Nhận hàng",
      description: "Nhận hàng tại nhà hoặc văn phòng của bạn."
    },
  ];

  return (
    <section className="py-16 px-4 md:px-0 bg-navy text-white" id="guide">
      <div className="container mx-auto text-center">
        <h2 className="text-4xl font-extrabold">Quy trình dịch vụ đơn giản</h2>
        <p className="mt-4 text-lg text-gray-300">Chỉ 4 bước để kiện hàng của bạn về đến Việt Nam.</p>

        <div className="mt-12 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {steps.map((step, index) => (
            <div key={index} className="flex flex-col items-center p-6 bg-navy-light rounded-lg shadow-xl border border-gray-700">
              {step.icon}
              <h3 className="text-2xl font-bold mt-2 mb-2">{step.title}</h3>
              <p className="text-gray-300">{step.description}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default ProcessSection;
